:host {
    display: block;
    width: 100%;
    height: 100%;
    padding: 0;
    margin: 0;
}

.sensor-container {
    font-family: 'Roboto', Arial, sans-serif;
    background-color: #ffffff00;
    width: 100%;
    height: 100%;
    box-sizing: border-box;
    padding: 8px;
}

.metric-card {
    background-color: #ffffff;
    border-radius: 8px;
    padding: 0;
    display: flex;
    flex-direction: column;
    height: 100%;
    box-sizing: border-box;
    overflow: hidden;
}

.static-table-wrapper {
    width: 100%;
    height: 100%;
    overflow: auto;
}

/* ===== TABLE ===== */

.static-table {
    width: 100%;
    border-collapse: collapse;
    table-layout: fixed;
}

/* ===== HEADER ===== */

.static-table thead th {
    font-weight: 600;
    text-transform: uppercase;
    font-size: 12px;
    letter-spacing: 0.5px;
    text-align: center;
    position: sticky;
    top: 0;
    z-index: 1;
}

/* ===== CELLS ===== */

.static-table td {
    text-align: center;
    vertical-align: middle;
    transition: background-color 0.3s ease, color 0.3s ease;
}

.static-table tbody tr:hover {
    background-color: rgba(0, 0, 0, 0.02);
}

/* ===== CLICKABLE CELL HOVER ANIMATION ===== */

.static-table td.cell-clickable {
    cursor: pointer;
    transition: background-color 0.18s ease, color 0.3s ease, filter 0.18s ease, outline 0.12s ease;
    outline: 2px solid transparent;
    outline-offset: -2px;
}

.static-table td.cell-clickable:hover {
    background-color: rgba(238, 118, 35, 0.09) !important;
    outline-color: rgba(238, 118, 35, 0.35);
    filter: brightness(0.96) drop-shadow(0 2px 5px rgba(0, 0, 0, 0.13));
}

/* ===== CELL CONTENT TYPES ===== */

.cell-content {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 4px;
    min-height: 24px;
}

.cell-content .material-icons {
    font-size: 20px;
    vertical-align: middle;
}

.cell-content .cell-icon-only .material-icons {
    font-size: 24px;
}

.cell-value-text {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.cell-unit-text {
    white-space: nowrap;
    font-size: 0.85em;
    opacity: 0.75;
    margin-left: 2px;
}

/* ===== CONDITIONAL ICON ===== */

.cell-cond-icon {
    display: inline-flex;
    align-items: center;
    margin-right: 4px;
}

.cell-cond-icon img {
    width: 18px;
    height: 18px;
    object-fit: contain;
}

/* ===== ALTERNATING ROW COLORS ===== */

.static-table tbody tr:nth-child(even) {
    background-color: rgba(0, 0, 0, 0.02);
}

.static-table tbody tr:nth-child(odd) {
    background-color: #ffffff;
}

