self.onInit = function () {
    var settings = self.ctx.settings;

    // Store parsed cell definitions
    self.ctx.cellMap = {};    // "row_col" -> { type, value }
    self.ctx.valueCells = []; // cells of type 'value' for data binding

    var rowCount = settings.rowCount || 3;
    var colCount = settings.colCount || 3;

    // Parse cell definitions from flat settings (row1_c1_type, row1_c1_value, etc.)
    for (var r = 1; r <= rowCount; r++) {
        for (var c = 1; c <= colCount; c++) {
            var prefix = 'row' + r + '_c' + c;
            var cellType = settings[prefix + '_type'] || 'text';
            var cellValue = settings[prefix + '_value'] || '';

            var cellUnit = (cellType === 'value') ? (settings[prefix + '_unit'] || '') : '';

            var cellDef = {
                r: r,
                c: c,
                type: cellType,
                value: cellValue,
                unit: cellUnit
            };

            self.ctx.cellMap[r + '_' + c] = cellDef;

            if (cellType === 'value') {
                cellDef.key = cellValue; // data key name
                self.ctx.valueCells.push(cellDef);
            }
        }
    }

    // Parse conditions
    self.ctx.conditions = [];
    if (settings.enableConditions) {
        for (var ci = 1; ci <= 5; ci++) {
            var condVal = settings['condValue' + ci];
            if (condVal !== undefined && condVal !== '') {
                self.ctx.conditions.push({
                    operator: settings['condOperator' + ci] || 'eq',
                    value: condVal,
                    color: settings['condColor' + ci] || '',
                    textColor: settings['condTextColor' + ci] || '',
                    svg: settings['condSvg' + ci] || '',
                    hideValue: settings['condHideValue' + ci] || false
                });
            }
        }
    }

    // Build the table
    self.buildTable();

    // Make widget card auto-size to fit table content
    var $container = self.ctx.$container;
    $container.css({ 'overflow': 'visible', 'height': 'auto' });
    $container.parents().each(function () {
        var $el = $(this);
        // Stop at the dashboard row/grid level
        if ($el.hasClass('tb-widget-container') || $el.hasClass('gridster-item') || $el.hasClass('mat-tab-body-content')) {
            return false; // break
        }
        $el.css({ 'overflow': 'visible', 'height': 'auto' });
    });
}

self.buildTable = function () {
    var settings = self.ctx.settings;
    var $wrapper = $('#wd-table-wrapper', self.ctx.$container);
    $wrapper.empty();

    var rowCount = settings.rowCount || 3;
    var colCount = settings.colCount || 3;
    var showHeaders = settings.showHeaders !== false;
    var headerBgColor = settings.headerBgColor || '#EE7623';
    var headerTextColor = settings.headerTextColor || '#FFFFFF';
    var borderColor = settings.borderColor || '#E0E0E0';
    var cellPadding = settings.cellPadding || 8;
    var fontSize = settings.fontSize || 14;

    // Get headers from individual settings fields
    var headers = [];
    for (var h = 1; h <= colCount; h++) {
        headers.push(settings['header' + h] || ('Columna ' + h));
    }

    // Create table element
    var $table = $('<table class="static-table"></table>');
    $table.css('font-size', fontSize + 'px');

    // Build header row
    if (showHeaders) {
        var $thead = $('<thead></thead>');
        var $headerRow = $('<tr></tr>');

        for (var hi = 0; hi < colCount; hi++) {
            var $th = $('<th></th>');
            $th.text(headers[hi]);
            $th.css({
                'background-color': headerBgColor,
                'color': headerTextColor,
                'padding': cellPadding + 'px',
                'border': '1px solid ' + borderColor
            });
            $headerRow.append($th);
        }
        $thead.append($headerRow);
        $table.append($thead);
    }

    // Build body rows
    var $tbody = $('<tbody></tbody>');

    for (var r = 1; r <= rowCount; r++) {
        var $row = $('<tr></tr>');

        for (var c = 1; c <= colCount; c++) {
            var $td = $('<td></td>');
            $td.css({
                'padding': cellPadding + 'px',
                'border': '1px solid ' + borderColor
            });
            $td.attr('id', 'cell-' + r + '-' + c);
            $td.data('row', r).data('col', c);
            $td.on('click', function (e) {
                self.handleCellClick(e, $(this).data('row'), $(this).data('col'));
            });

            // Mark cells that have a configured action with a special class
            if (self.ctx.actionsApi) {
                var cellDescs = self.ctx.actionsApi.getActionDescriptors('cellClick_r' + r + '_c' + c);
                if (!cellDescs || !cellDescs.length) {
                    cellDescs = self.ctx.actionsApi.getActionDescriptors('cellClick_col' + c);
                }
                if (cellDescs && cellDescs.length) {
                    $td.addClass('cell-clickable');
                }
            }

            var cellDef = self.ctx.cellMap[r + '_' + c];

            if (cellDef) {
                var $content = self.renderCell(cellDef);
                $td.append($content);
            }

            $row.append($td);
        }

        $tbody.append($row);
    }

    $table.append($tbody);
    $wrapper.append($table);
}

self.renderCell = function (cellDef) {
    var $content = $('<div class="cell-content"></div>');

    switch (cellDef.type) {
        case 'text':
            var $text = $('<span class="cell-value-text"></span>');
            $text.text(cellDef.value || '');
            $content.append($text);
            break;

        case 'icon':
            var $icon = $('<span class="material-icons"></span>');
            $icon.text(cellDef.value || 'help_outline');
            $content.addClass('cell-icon-only');
            $content.append($icon);
            break;

        case 'value':
            // Placeholder — will be filled by onDataUpdated
            var $val = $('<span class="cell-value-text" id="val-' + cellDef.r + '-' + cellDef.c + '">-</span>');
            $content.append($val);
            if (cellDef.unit) {
                var $unit = $('<span class="cell-unit-text" id="unit-' + cellDef.r + '-' + cellDef.c + '"></span>');
                $unit.text(cellDef.unit);
                $content.append($unit);
            }
            break;

        default:
            break;
    }

    return $content;
}

self.onDataUpdated = function () {
    if (!self.ctx.defaultSubscription || !self.ctx.defaultSubscription.data) return;

    var data = self.ctx.defaultSubscription.data;

    // Build map: label -> last value, and label -> entity info
    var dataMap = {};
    self.ctx.labelEntityMap = {};
    for (var d = 0; d < data.length; d++) {
        var entry = data[d];
        var keyName = entry.dataKey.label || entry.dataKey.name;
        if (entry.data && entry.data.length > 0) {
            var lastPoint = entry.data[entry.data.length - 1];
            dataMap[keyName] = lastPoint[1];
        }
        if (entry.datasource && entry.datasource.entity) {
            self.ctx.labelEntityMap[keyName] = {
                entityId:    entry.datasource.entity.id,
                entityName:  entry.datasource.entityName,
                entityLabel: entry.datasource.entityLabel || entry.datasource.entityName
            };
        }
    }

    var decimals = self.ctx.settings.decimals;
    if (typeof decimals === 'undefined') decimals = 1;

    // Update each value cell
    for (var i = 0; i < self.ctx.valueCells.length; i++) {
        var cell = self.ctx.valueCells[i];
        var rawValue = dataMap[cell.key];
        var displayValue = '-';
        var $valElem = $('#val-' + cell.r + '-' + cell.c, self.ctx.$container);
        var $tdElem = $('#cell-' + cell.r + '-' + cell.c, self.ctx.$container);
        var $unitElem = $('#unit-' + cell.r + '-' + cell.c, self.ctx.$container);

        if (rawValue !== undefined && rawValue !== null) {
            var numVal = parseFloat(rawValue);

            if (!isNaN(numVal)) {
                displayValue = numVal.toFixed(decimals);
            } else {
                displayValue = rawValue;
            }
        }

        // Apply conditional formatting
        self.applyConditions($tdElem, $valElem, $unitElem, rawValue, displayValue);
    }
}

self.handleCellClick = function (e, row, col) {
    // Cell-specific action takes priority, falls back to column action
    var descriptors = self.ctx.actionsApi.getActionDescriptors('cellClick_r' + row + '_c' + col);
    if (!descriptors || !descriptors.length) {
        descriptors = self.ctx.actionsApi.getActionDescriptors('cellClick_col' + col);
    }
    if (!descriptors || !descriptors.length) return;

    var entityId = null, entityName = null, entityLabel = null;
    var cellDef = self.ctx.cellMap[row + '_' + col];

    if (cellDef && cellDef.type === 'value' && self.ctx.labelEntityMap) {
        var info = self.ctx.labelEntityMap[cellDef.key];
        if (info) {
            entityId    = info.entityId;
            entityName  = info.entityName;
            entityLabel = info.entityLabel;
        }
    }

    self.ctx.actionsApi.handleWidgetAction(e, descriptors[0], entityId, entityName, null, entityLabel);
}

self.applyConditions = function ($td, $valElem, $unitElem, rawValue, displayValue) {
    // Reset styles
    $td.css('background-color', '');
    $td.css('color', '');

    // Remove previous condition SVG
    $td.find('.cell-cond-icon').remove();

    // Show value and unit elements by default
    $valElem.show();
    if ($unitElem && $unitElem.length) $unitElem.show();

    // Set the display value
    $valElem.text(displayValue);

    if (!self.ctx.conditions || self.ctx.conditions.length === 0) return;
    if (rawValue === undefined || rawValue === null) return;

    for (var i = 0; i < self.ctx.conditions.length; i++) {
        var cond = self.ctx.conditions[i];
        var match = self.evaluateCondition(cond.operator, rawValue, cond.value);

        if (match) {
            if (cond.color) {
                $td.css('background-color', cond.color);
                $td.css('color', cond.textColor ? cond.textColor : self.getContrastColor(cond.color));
            } else if (cond.textColor) {
                $td.css('color', cond.textColor);
            }

            if (cond.svg) {
                var $svg = $('<span class="cell-cond-icon"><img src="' + cond.svg + '" alt="" /></span>');
                $td.find('.cell-content').prepend($svg);
            }

            if (cond.hideValue) {
                $valElem.hide();
                if ($unitElem && $unitElem.length) $unitElem.hide();
            }

            break; // First match wins
        }
    }
}

self.evaluateCondition = function (operator, rawValue, targetValue) {
    var numRaw = parseFloat(rawValue);
    var numTarget = parseFloat(targetValue);
    var isNumeric = !isNaN(numRaw) && !isNaN(numTarget);

    switch (operator) {
        case 'eq':
            if (isNumeric) return numRaw === numTarget;
            return String(rawValue).toLowerCase() === String(targetValue).toLowerCase();

        case 'neq':
            if (isNumeric) return numRaw !== numTarget;
            return String(rawValue).toLowerCase() !== String(targetValue).toLowerCase();

        case 'gt':
            if (isNumeric) return numRaw > numTarget;
            return String(rawValue) > String(targetValue);

        case 'lt':
            if (isNumeric) return numRaw < numTarget;
            return String(rawValue) < String(targetValue);

        case 'gte':
            if (isNumeric) return numRaw >= numTarget;
            return String(rawValue) >= String(targetValue);

        case 'lte':
            if (isNumeric) return numRaw <= numTarget;
            return String(rawValue) <= String(targetValue);

        case 'contains':
            return String(rawValue).toLowerCase().indexOf(String(targetValue).toLowerCase()) !== -1;

        default:
            return String(rawValue).toLowerCase() === String(targetValue).toLowerCase();
    }
}

self.getContrastColor = function (hexColor) {
    if (!hexColor || hexColor.length < 7) return '#000000';

    var r = parseInt(hexColor.substr(1, 2), 16);
    var g = parseInt(hexColor.substr(3, 2), 16);
    var b = parseInt(hexColor.substr(5, 2), 16);

    var brightness = (r * 299 + g * 587 + b * 114) / 1000;

    return brightness > 128 ? '#000000' : '#FFFFFF';
}

self.onResize = function () {
}

self.typeParameters = function () {
    return {
        maxDatasources: -1,
        maxDataKeys: -1,
        dataKeysOptional: true
    };
}

self.actionSources = function () {
    var sources = {};
    var colCount = (self.ctx && self.ctx.settings && self.ctx.settings.colCount) || 10;
    var rowCount = (self.ctx && self.ctx.settings && self.ctx.settings.rowCount) || 20;

    // Column-level actions (apply to all cells in that column)
    for (var c = 1; c <= colCount; c++) {
        sources['cellClick_col' + c] = {
            name: 'Click Columna ' + c,
            multiple: false
        };
    }

    // Cell-level actions (override column action for a specific cell)
    for (var r = 1; r <= rowCount; r++) {
        for (var c = 1; c <= colCount; c++) {
            sources['cellClick_r' + r + '_c' + c] = {
                name: 'Click Fila ' + r + ' Col ' + c,
                multiple: false
            };
        }
    }

    return sources;
}

self.onDestroy = function () {
}

